import{_ as t,c as i,o as s,a1 as e}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"DMペアリングとアクセス制御：あなたのAIアシスタントを保護する | Clawdbotチュートリアル","description":"ClawdbotのDMペアリング保護メカニズムを理解し、CLIを使用して不明な送信者のペアリング要求を承認する方法、保留中の要求を一覧表示する方法、許可リストを管理する方法を学びます。本チュートリアルでは、ペアリングフロー、CLIコマンドの使用、アクセスポリシーの設定、セキュリティベストプラクティスを完全に説明し、一般的なエラーのトラブルシューティングとdoctorコマンドを含みます。","frontmatter":{"title":"DMペアリングとアクセス制御：あなたのAIアシスタントを保護する | Clawdbotチュートリアル","sidebarTitle":"不明なユーザーのアクセスを管理","subtitle":"DMペアリングとアクセス制御：あなたのAIアシスタントを保護する","description":"ClawdbotのDMペアリング保護メカニズムを理解し、CLIを使用して不明な送信者のペアリング要求を承認する方法、保留中の要求を一覧表示する方法、許可リストを管理する方法を学びます。本チュートリアルでは、ペアリングフロー、CLIコマンドの使用、アクセスポリシーの設定、セキュリティベストプラクティスを完全に説明し、一般的なエラーのトラブルシューティングとdoctorコマンドを含みます。","tags":["入門","セキュリティ","ペアリング","アクセス制御"],"prerequisite":["start-gateway-startup"],"order":50},"headers":[],"relativePath":"ja/moltbot/moltbot/start/pairing-approval/index.md","filePath":"ja/moltbot/moltbot/start/pairing-approval/index.md"}'),l={name:"ja/moltbot/moltbot/start/pairing-approval/index.md"};function o(n,a,r,d,p,c){return s(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="dmペアリングとアクセス制御-あなたのaiアシスタントを保護する" tabindex="-1">DMペアリングとアクセス制御：あなたのAIアシスタントを保護する <a class="header-anchor" href="#dmペアリングとアクセス制御-あなたのaiアシスタントを保護する" aria-label="Permalink to &quot;DMペアリングとアクセス制御：あなたのAIアシスタントを保護する&quot;">​</a></h1><h2 id="このチュートリアルで学べること" tabindex="-1">このチュートリアルで学べること <a class="header-anchor" href="#このチュートリアルで学べること" aria-label="Permalink to &quot;このチュートリアルで学べること&quot;">​</a></h2><p>このチュートリアルを完了すると、以下のことができるようになります：</p><ul><li>✅ デフォルトのDMペアリング保護メカニズムを理解する</li><li>✅ 不明な送信者のペアリング要求を承認する</li><li>✅ 保留中のペアリング要求を一覧表示・管理する</li><li>✅ 異なるDMアクセスポリシー（pairing/allowlist/open）を設定する</li><li>✅ doctorコマンドを実行してセキュリティ設定を確認する</li></ul><h2 id="現在直面している課題" tabindex="-1">現在直面している課題 <a class="header-anchor" href="#現在直面している課題" aria-label="Permalink to &quot;現在直面している課題&quot;">​</a></h2><p>WhatsAppやTelegramチャネルを設定し、AIアシスタントと対話したいが、以下の問題に直面しているかもしれません：</p><ul><li>「なぜ見知らぬ人がメッセージを送ってきても、Clawdbotが返信しないのか？」</li><li>「ペアリングコードを受け取ったが、どういう意味か分からない」</li><li>「誰かの要求を承認したいが、どのコマンドを使えばよいか分からない」</li><li>「現在、誰が承認待ちかどう確認するか？」</li></ul><p>朗報：<strong>ClawdbotはデフォルトでDMペアリング保護を有効にしています</strong>。これは、あなたが承認した送信者のみがAIアシスタントと対話できるようにするためです。</p><h2 id="いつこの機能を使うか" tabindex="-1">いつこの機能を使うか <a class="header-anchor" href="#いつこの機能を使うか" aria-label="Permalink to &quot;いつこの機能を使うか&quot;">​</a></h2><p>以下のニーズがある場合：</p><ul><li>🛡 <strong>プライバシー保護</strong>：信頼できる人だけがAIアシスタントと対話できるようにする</li><li>✅ <strong>不明なユーザーの承認</strong>：新しい送信者がAIアシスタントにアクセスできるようにする</li><li>🔒 <strong>厳格なアクセス制御</strong>：特定のユーザーのアクセス権を制限する</li><li>📋 <strong>一括管理</strong>：保留中のすべてのペアリング要求を表示・管理する</li></ul><hr><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="dmペアリングとは" tabindex="-1">DMペアリングとは？ <a class="header-anchor" href="#dmペアリングとは" aria-label="Permalink to &quot;DMペアリングとは？&quot;">​</a></h3><p>Clawdbotは実際のメッセージプラットフォーム（WhatsApp、Telegram、Slackなど）に接続し、これらのプラットフォーム上の<strong>DM（ダイレクトメッセージ）はデフォルトで信頼できない入力として扱われます</strong>。</p><p>AIアシスタントを保護するために、Clawdbotは<strong>ペアリングメカニズム</strong>を提供しています：</p><div class="info custom-block"><p class="custom-block-title">ペアリングフロー</p><ol><li>不明な送信者がメッセージを送信する</li><li>Clawdbotがその送信者が承認されていないことを検知する</li><li>Clawdbotが<strong>ペアリングコード</strong>（8文字）を返す</li><li>送信者はペアリングコードをあなたに提供する必要がある</li><li>あなたはCLIを使用してそのコードを承認する</li><li>送信者IDが許可リストに追加される</li><li>送信者はAIアシスタントと通常通り対話できる</li></ol></div><h3 id="デフォルトのdmポリシー" tabindex="-1">デフォルトのDMポリシー <a class="header-anchor" href="#デフォルトのdmポリシー" aria-label="Permalink to &quot;デフォルトのDMポリシー&quot;">​</a></h3><p><strong>すべてのチャネルでデフォルトで <code>dmPolicy=&quot;pairing&quot;</code> が使用されます</strong>。これは以下を意味します：</p><table tabindex="0"><thead><tr><th>ポリシー</th><th>動作</th></tr></thead><tbody><tr><td><code>pairing</code></td><td>不明な送信者はペアリングコードを受け取り、メッセージは処理されない（デフォルト）</td></tr><tr><td><code>allowlist</code></td><td><code>allowFrom</code> リスト内の送信者のみ許可</td></tr><tr><td><code>open</code></td><td>すべての送信者を許可（明示的に <code>&quot;*&quot;</code> を設定する必要あり）</td></tr><tr><td><code>disabled</code></td><td>DM機能を完全に無効化</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">セキュリティリマインダー</p><p>デフォルトの <code>pairing</code> モードが最も安全な選択肢です。特別な要件がない限り、<code>open</code> モードに変更しないでください。</p></div><hr><h2 id="🎒-始める前の準備" tabindex="-1">🎒 始める前の準備 <a class="header-anchor" href="#🎒-始める前の準備" aria-label="Permalink to &quot;🎒 始める前の準備&quot;">​</a></h2><p>以下が完了していることを確認してください：</p><ul><li>[x] <a href="./../getting-started/">クイックスタート</a> チュートリアルを完了した</li><li>[x] <a href="./../gateway-startup/">Gatewayの起動</a> チュートリアルを完了した</li><li>[x] 少なくとも1つのメッセージチャネル（WhatsApp、Telegram、Slackなど）を設定した</li><li>[x] Gatewayが実行中である</li></ul><hr><h2 id="手順通り進める" tabindex="-1">手順通り進める <a class="header-anchor" href="#手順通り進める" aria-label="Permalink to &quot;手順通り進める&quot;">​</a></h2><h3 id="ステップ1-ペアリングコードの仕組みを理解する" tabindex="-1">ステップ1：ペアリングコードの仕組みを理解する <a class="header-anchor" href="#ステップ1-ペアリングコードの仕組みを理解する" aria-label="Permalink to &quot;ステップ1：ペアリングコードの仕組みを理解する&quot;">​</a></h3><p>不明な送信者があなたのClawdbotにメッセージを送信すると、以下のような返信を受け取ります：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Clawdbot: access not configured.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Telegram ID: 123456789</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pairing code: AB3D7X9K</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ask the bot owner to approve with:</span></span>
<span class="line"><span>clawdbot pairing approve telegram &lt;code&gt;</span></span></code></pre></div><p><strong>ペアリングコードの主な特性</strong>（出典：<code>src/pairing/pairing-store.ts</code>）：</p><ul><li><strong>8文字</strong>：入力と記憶が簡単</li><li><strong>大文字と数字</strong>：混乱を防ぐ</li><li><strong>紛らわしい文字を除外</strong>：0、O、1、Iは含まない</li><li><strong>1時間の有効期間</strong>：経過すると自動的に失効</li><li><strong>最大3つの保留中の要求を保持</strong>：超過すると最も古い要求を自動的にクリア</li></ul><h3 id="ステップ2-保留中のペアリング要求を一覧表示する" tabindex="-1">ステップ2：保留中のペアリング要求を一覧表示する <a class="header-anchor" href="#ステップ2-保留中のペアリング要求を一覧表示する" aria-label="Permalink to &quot;ステップ2：保留中のペアリング要求を一覧表示する&quot;">​</a></h3><p>ターミナルで以下のコマンドを実行します：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span></span></code></pre></div><p><strong>以下が表示されるはずです</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pairing requests (1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────────┬────────────────┬────────┬──────────────────────┐</span></span>
<span class="line"><span>│ Code            │ ID            │ Meta   │ Requested            │</span></span>
<span class="line"><span>├──────────────────┼────────────────┼────────┼──────────────────────┤</span></span>
<span class="line"><span>│ AB3D7X9K        │ 123456789      │        │ 2026-01-27T10:30:00Z │</span></span>
<span class="line"><span>└──────────────────┴────────────────┴────────┴──────────────────────┘</span></span></code></pre></div><p>保留中の要求がない場合、以下が表示されます：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending telegram pairing requests.</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">対応チャネル</p><p>ペアリング機能は以下のチャネルをサポートしています：</p><ul><li>telegram</li><li>whatsapp</li><li>slack</li><li>discord</li><li>signal</li><li>imessage</li><li>msteams</li><li>googlechat</li><li>bluebubbles</li></ul></div><h3 id="ステップ3-ペアリング要求を承認する" tabindex="-1">ステップ3：ペアリング要求を承認する <a class="header-anchor" href="#ステップ3-ペアリング要求を承認する" aria-label="Permalink to &quot;ステップ3：ペアリング要求を承認する&quot;">​</a></h3><p>送信者から提供されたペアリングコードを使用してアクセスを承認します：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span></span></code></pre></div><p><strong>以下が表示されるはずです</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Approved telegram sender 123456789</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">承認後の効果</p><p>承認後、送信者ID（123456789）は自動的にそのチャネルの許可リストに追加され、以下の場所に保存されます： <code>~/.clawdbot/credentials/telegram-allowFrom.json</code></p></div><h3 id="ステップ4-送信者に通知する-オプション" tabindex="-1">ステップ4：送信者に通知する（オプション） <a class="header-anchor" href="#ステップ4-送信者に通知する-オプション" aria-label="Permalink to &quot;ステップ4：送信者に通知する（オプション）&quot;">​</a></h3><p>送信者に自動的に通知したい場合、<code>--notify</code> フラグを使用できます：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --notify</span></span></code></pre></div><p>送信者は以下のメッセージを受け取ります（出典：<code>src/channels/plugins/pairing-message.ts</code>）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Clawdbot access approved. Send a message to start chatting.</span></span></code></pre></div><p><strong>注意</strong>：<code>--notify</code> フラグはClawdbot Gatewayが実行中であり、そのチャネルがアクティブな状態であることを必要とします。</p><h3 id="ステップ5-送信者が正常に対話できることを確認する" tabindex="-1">ステップ5：送信者が正常に対話できることを確認する <a class="header-anchor" href="#ステップ5-送信者が正常に対話できることを確認する" aria-label="Permalink to &quot;ステップ5：送信者が正常に対話できることを確認する&quot;">​</a></h3><p>送信者に再度メッセージを送信してもらうと、AIアシスタントが正常に返信するはずです。</p><hr><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><p>以下のチェックを完了して、設定が正しいことを確認してください：</p><ul><li>[ ] <code>clawdbot pairing list &lt;channel&gt;</code> を実行すると、保留中の要求が表示される</li><li>[ ] <code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code> を使用して、正常に承認できる</li><li>[ ] 承認された送信者がAIアシスタントと正常に対話できる</li><li>[ ] ペアリングコードは1時間後に自動的に期限切れになる（再度メッセージを送信して確認可能）</li></ul><hr><h2 id="よくあるエラーと回避策" tabindex="-1">よくあるエラーと回避策 <a class="header-anchor" href="#よくあるエラーと回避策" aria-label="Permalink to &quot;よくあるエラーと回避策&quot;">​</a></h2><h3 id="エラー1-ペアリングコードが見つからない" tabindex="-1">エラー1：ペアリングコードが見つからない <a class="header-anchor" href="#エラー1-ペアリングコードが見つからない" aria-label="Permalink to &quot;エラー1：ペアリングコードが見つからない&quot;">​</a></h3><p><strong>エラーメッセージ</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending pairing request found for code: AB3D7X9K</span></span></code></pre></div><p><strong>考えられる原因</strong>：</p><ul><li>ペアリングコードが期限切れ（1時間経過）</li><li>ペアリングコードの入力ミス（大文字小文字を確認）</li><li>送信者が実際にメッセージを送信していない（ペアリングコードはメッセージを受信した場合のみ生成される）</li></ul><p><strong>解決方法</strong>：</p><ul><li>送信者に再度メッセージを送信してもらい、新しいペアリングコードを生成する</li><li>ペアリングコードが正しくコピーされているか確認する（大文字小文字に注意）</li></ul><h3 id="エラー2-チャネルがペアリングをサポートしていない" tabindex="-1">エラー2：チャネルがペアリングをサポートしていない <a class="header-anchor" href="#エラー2-チャネルがペアリングをサポートしていない" aria-label="Permalink to &quot;エラー2：チャネルがペアリングをサポートしていない&quot;">​</a></h3><p><strong>エラーメッセージ</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Channel xxx does not support pairing</span></span></code></pre></div><p><strong>考えられる原因</strong>：</p><ul><li>チャネル名のスペルミス</li><li>そのチャネルはペアリング機能をサポートしていない</li></ul><p><strong>解決方法</strong>：</p><ul><li><code>clawdbot pairing list</code> を実行して、サポートされているチャネルのリストを確認する</li><li>正しいチャネル名を使用する</li></ul><h3 id="エラー3-通知に失敗した" tabindex="-1">エラー3：通知に失敗した <a class="header-anchor" href="#エラー3-通知に失敗した" aria-label="Permalink to &quot;エラー3：通知に失敗した&quot;">​</a></h3><p><strong>エラーメッセージ</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Failed to notify requester: &lt;error details&gt;</span></span></code></pre></div><p><strong>考えられる原因</strong>：</p><ul><li>Gatewayが実行されていない</li><li>チャネル接続が切断されている</li><li>ネットワークの問題</li></ul><p><strong>解決方法</strong>：</p><ul><li>Gatewayが実行中であることを確認する</li><li>チャネル接続状態を確認する：<code>clawdbot channels status</code></li><li><code>--notify</code> フラグを使用せず、手動で送信者に通知する</li></ul><hr><h2 id="まとめ" tabindex="-1">まとめ <a class="header-anchor" href="#まとめ" aria-label="Permalink to &quot;まとめ&quot;">​</a></h2><p>このチュートリアルでは、ClawdbotのDMペアリング保護メカニズムについて学びました：</p><ul><li><strong>デフォルトで安全</strong>：すべてのチャネルはデフォルトで <code>pairing</code> モードを使用し、AIアシスタントを保護します</li><li><strong>ペアリングフロー</strong>：不明な送信者は8文字のペアリングコードを受け取り、CLIを使用して承認する必要があります</li><li><strong>管理コマンド</strong>： <ul><li><code>clawdbot pairing list &lt;channel&gt;</code>：保留中の要求を一覧表示</li><li><code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code>：ペアリングを承認</li></ul></li><li><strong>保存場所</strong>：許可リストは <code>~/.clawdbot/credentials/&lt;channel&gt;-allowFrom.json</code> に保存されます</li><li><strong>自動期限切れ</strong>：ペアリング要求は1時間後に自動的に失効します</li></ul><p>覚えておいてください：<strong>ペアリングメカニズムはClawdbotのセキュリティの基盤</strong>であり、承認したユーザーのみがAIアシスタントと対話できるようにします。</p><hr><h2 id="次回の予告" tabindex="-1">次回の予告 <a class="header-anchor" href="#次回の予告" aria-label="Permalink to &quot;次回の予告&quot;">​</a></h2><blockquote><p>次のレッスンでは、<strong><a href="./../../faq/troubleshooting/">トラブルシューティング：一般的な問題の解決</a></strong> を学びます。</p><p>学べること：</p><ul><li>迅速な診断とシステム状態の確認</li><li>Gatewayの起動、チャネル接続、認証エラーなどの問題を解決する</li><li>ツール呼び出しの失敗とパフォーマンス最適化のトラブルシューティング方法</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの位置を表示</strong></summary><blockquote><p>更新日時：2026-01-27</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>ペアリングコード生成（8文字、紛らわしい文字を除外）</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L173-L181" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>173-181</td></tr><tr><td>ペアリング要求の保存とTTL（1時間）</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L11-L14" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>11-14</td></tr><tr><td>ペアリング承認コマンド</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/cli/pairing-cli.ts#L107-L143" target="_blank" rel="noreferrer"><code>src/cli/pairing-cli.ts</code></a></td><td>107-143</td></tr><tr><td>ペアリングコードメッセージ生成</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-messages.ts#L4-L20" target="_blank" rel="noreferrer"><code>src/pairing/pairing-messages.ts</code></a></td><td>4-20</td></tr><tr><td>許可リストの保存</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L457-L461" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>457-461</td></tr><tr><td><code>pairing</code> をサポートするチャネルリスト</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/channels/plugins/pairing.ts#L11-L16" target="_blank" rel="noreferrer"><code>src/channels/plugins/pairing.ts</code></a></td><td>11-16</td></tr><tr><td>デフォルトのDMポリシー（pairing）</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/config/zod-schema.providers-core.ts#L93" target="_blank" rel="noreferrer"><code>src/config/zod-schema.providers-core.ts</code></a></td><td>93</td></tr></tbody></table><p><strong>重要な定数</strong>：</p><ul><li><code>PAIRING_CODE_LENGTH = 8</code>：ペアリングコードの長さ</li><li><code>PAIRING_CODE_ALPHABET = &quot;ABCDEFGHJKLMNPQRSTUVWXYZ23456789&quot;</code>：ペアリングコードの文字セット（0O1Iを除外）</li><li><code>PAIRING_PENDING_TTL_MS = 60 * 60 * 1000</code>：ペアリング要求の有効期間（1時間）</li><li><code>PAIRING_PENDING_MAX = 3</code>：保留中の要求の最大数</li></ul><p><strong>重要な関数</strong>：</p><ul><li><code>approveChannelPairingCode()</code>：ペアリングコードを承認し、許可リストに追加する</li><li><code>listChannelPairingRequests()</code>：保留中のペアリング要求を一覧表示する</li><li><code>upsertChannelPairingRequest()</code>：ペアリング要求を作成または更新する</li><li><code>addChannelAllowFromStoreEntry()</code>：許可リストに送信者を追加する</li></ul></details>`,92)])])}const b=t(l,[["render",o]]);export{g as __pageData,b as default};
